-- ==========================================================
-- MASTER DATA RESTORE BATERIAQ (FULL SCHEMA & DATA RECOVERY)
-- ==========================================================

-- 1. LIMPIEZA TOTAL
DROP TABLE IF EXISTS "_EnrolledOppositions" CASCADE;
DROP TABLE IF EXISTS "test_answers" CASCADE;
DROP TABLE IF EXISTS "tests" CASCADE;
DROP TABLE IF EXISTS "user_achievements" CASCADE;
DROP TABLE IF EXISTS "achievements" CASCADE;
DROP TABLE IF EXISTS "bookmarks" CASCADE;
DROP TABLE IF EXISTS "mistakes" CASCADE;
DROP TABLE IF EXISTS "user_progress" CASCADE;
DROP TABLE IF EXISTS "study_plans" CASCADE;
DROP TABLE IF EXISTS "streaks" CASCADE;
DROP TABLE IF EXISTS "sessions" CASCADE;
DROP TABLE IF EXISTS "questions" CASCADE;
DROP TABLE IF EXISTS "subtopics" CASCADE;
DROP TABLE IF EXISTS "topics" CASCADE;
DROP TABLE IF EXISTS "oppositions" CASCADE;
DROP TABLE IF EXISTS "users" CASCADE;

-- 2. ENUMS (PRISMA COMPATIBLE)
DO $$ BEGIN
    CREATE TYPE "Role" AS ENUM ('USER', 'ADMIN');
EXCEPTION WHEN duplicate_object THEN null; END $$;

DO $$ BEGIN
    CREATE TYPE "Difficulty" AS ENUM ('EASY', 'MEDIUM', 'HARD');
EXCEPTION WHEN duplicate_object THEN null; END $$;

DO $$ BEGIN
    CREATE TYPE "TestType" AS ENUM ('QUICK', 'TOPIC', 'EXAM_SIMULATION', 'ERROR_REVIEW', 'CUSTOM');
EXCEPTION WHEN duplicate_object THEN null; END $$;

DO $$ BEGIN
    CREATE TYPE "AchievementType" AS ENUM ('STREAK', 'ACCURACY', 'VOLUME', 'MASTERY', 'SPEED');
EXCEPTION WHEN duplicate_object THEN null; END $$;

-- 3. SCHEMA CREATION
CREATE TABLE "users" (
    "id" TEXT PRIMARY KEY,
    "name" VARCHAR(100) NOT NULL,
    "email" VARCHAR(255) UNIQUE NOT NULL,
    "password_hash" TEXT NOT NULL,
    "role" "Role" NOT NULL DEFAULT 'USER',
    "exam_date" TIMESTAMP(3),
    "dark_mode" BOOLEAN NOT NULL DEFAULT false,
    "notifications" BOOLEAN NOT NULL DEFAULT true,
    "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "updated_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE "sessions" (
    "id" TEXT PRIMARY KEY,
    "user_id" TEXT NOT NULL REFERENCES "users"("id") ON DELETE CASCADE,
    "refresh_token" TEXT UNIQUE NOT NULL,
    "user_agent" VARCHAR(500),
    "ip_address" VARCHAR(45),
    "expires_at" TIMESTAMP(3) NOT NULL,
    "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE "oppositions" (
    "id" TEXT PRIMARY KEY,
    "name" VARCHAR(200) NOT NULL,
    "description" TEXT,
    "category" VARCHAR(100),
    "icon" VARCHAR(50),
    "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "updated_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "creator_id" TEXT REFERENCES "users"("id") ON DELETE SET NULL
);

CREATE TABLE "topics" (
    "id" TEXT PRIMARY KEY,
    "title" VARCHAR(200) NOT NULL,
    "description" TEXT,
    "order" INTEGER NOT NULL DEFAULT 0,
    "icon" VARCHAR(50),
    "color" VARCHAR(7),
    "is_active" BOOLEAN NOT NULL DEFAULT true,
    "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "updated_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "opposition_id" TEXT REFERENCES "oppositions"("id") ON DELETE CASCADE,
    "creator_id" TEXT REFERENCES "users"("id") ON DELETE SET NULL
);

CREATE TABLE "subtopics" (
    "id" TEXT PRIMARY KEY,
    "title" VARCHAR(200) NOT NULL,
    "order" INTEGER NOT NULL DEFAULT 0,
    "topic_id" TEXT NOT NULL REFERENCES "topics"("id") ON DELETE CASCADE,
    "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "updated_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE "questions" (
    "id" TEXT PRIMARY KEY,
    "topic_id" TEXT NOT NULL REFERENCES "topics"("id") ON DELETE CASCADE,
    "question_text" TEXT NOT NULL,
    "options" JSONB NOT NULL,
    "correct_index" INTEGER NOT NULL,
    "explanation" TEXT,
    "difficulty" "Difficulty" NOT NULL DEFAULT 'MEDIUM',
    "is_active" BOOLEAN NOT NULL DEFAULT true,
    "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "updated_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "subtopic_id" TEXT REFERENCES "subtopics"("id") ON DELETE SET NULL
);

CREATE TABLE "user_progress" (
    "id" TEXT PRIMARY KEY,
    "user_id" TEXT NOT NULL REFERENCES "users"("id") ON DELETE CASCADE,
    "question_id" TEXT NOT NULL REFERENCES "questions"("id") ON DELETE CASCADE,
    "is_correct" BOOLEAN NOT NULL,
    "attempts" INTEGER NOT NULL DEFAULT 1,
    "last_attempt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "is_mastered" BOOLEAN NOT NULL DEFAULT false,
    "response_time" INTEGER,
    "next_review" TIMESTAMP(3),
    "ease_factor" DOUBLE PRECISION NOT NULL DEFAULT 2.5,
    "interval" INTEGER NOT NULL DEFAULT 1
);
CREATE UNIQUE INDEX "user_progress_user_id_question_id_key" ON "user_progress"("user_id", "question_id");

CREATE TABLE "streaks" (
    "id" TEXT PRIMARY KEY,
    "user_id" TEXT UNIQUE NOT NULL REFERENCES "users"("id") ON DELETE CASCADE,
    "current_streak" INTEGER NOT NULL DEFAULT 0,
    "max_streak" INTEGER NOT NULL DEFAULT 0,
    "last_study_date" TIMESTAMP(3),
    "current_no_fail" INTEGER NOT NULL DEFAULT 0,
    "max_no_fail" INTEGER NOT NULL DEFAULT 0
);

CREATE TABLE "tests" (
    "id" TEXT PRIMARY KEY,
    "user_id" TEXT NOT NULL REFERENCES "users"("id") ON DELETE CASCADE,
    "type" "TestType" NOT NULL DEFAULT 'QUICK',
    "score" DOUBLE PRECISION NOT NULL DEFAULT 0,
    "total_questions" INTEGER NOT NULL,
    "correct_answers" INTEGER NOT NULL DEFAULT 0,
    "time_spent" INTEGER NOT NULL DEFAULT 0,
    "time_limit" INTEGER,
    "penalize_errors" BOOLEAN NOT NULL DEFAULT false,
    "is_completed" BOOLEAN NOT NULL DEFAULT false,
    "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "completed_at" TIMESTAMP(3)
);

CREATE TABLE "test_answers" (
    "id" TEXT PRIMARY KEY,
    "test_id" TEXT NOT NULL REFERENCES "tests"("id") ON DELETE CASCADE,
    "user_id" TEXT NOT NULL REFERENCES "users"("id") ON DELETE CASCADE,
    "question_id" TEXT NOT NULL REFERENCES "questions"("id") ON DELETE CASCADE,
    "selected_index" INTEGER,
    "is_correct" BOOLEAN,
    "response_time" INTEGER,
    "answered_at" TIMESTAMP(3)
);
CREATE UNIQUE INDEX "test_answers_test_id_question_id_key" ON "test_answers"("test_id", "question_id");

CREATE TABLE "bookmarks" (
    "id" TEXT PRIMARY KEY,
    "user_id" TEXT NOT NULL REFERENCES "users"("id") ON DELETE CASCADE,
    "question_id" TEXT NOT NULL REFERENCES "questions"("id") ON DELETE CASCADE,
    "note" TEXT,
    "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP
);
CREATE UNIQUE INDEX "bookmarks_user_id_question_id_key" ON "bookmarks"("user_id", "question_id");

CREATE TABLE "mistakes" (
    "id" TEXT PRIMARY KEY,
    "user_id" TEXT NOT NULL REFERENCES "users"("id") ON DELETE CASCADE,
    "question_id" TEXT NOT NULL REFERENCES "questions"("id") ON DELETE CASCADE,
    "mistake_count" INTEGER NOT NULL DEFAULT 1,
    "last_mistake" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "is_resolved" BOOLEAN NOT NULL DEFAULT false
);
CREATE UNIQUE INDEX "mistakes_user_id_question_id_key" ON "mistakes"("user_id", "question_id");

CREATE TABLE "study_plans" (
    "id" TEXT PRIMARY KEY,
    "user_id" TEXT NOT NULL REFERENCES "users"("id") ON DELETE CASCADE,
    "date" DATE NOT NULL,
    "topic_ids" JSONB NOT NULL,
    "description" TEXT,
    "is_completed" BOOLEAN NOT NULL DEFAULT false,
    "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP
);
CREATE UNIQUE INDEX "study_plans_user_id_date_key" ON "study_plans"("user_id", "date");

CREATE TABLE "achievements" (
    "id" TEXT PRIMARY KEY,
    "name" VARCHAR(100) NOT NULL,
    "description" TEXT NOT NULL,
    "icon" VARCHAR(50) NOT NULL,
    "type" "AchievementType" NOT NULL,
    "threshold" INTEGER NOT NULL,
    "is_active" BOOLEAN NOT NULL DEFAULT true
);

CREATE TABLE "user_achievements" (
    "id" TEXT PRIMARY KEY,
    "user_id" TEXT NOT NULL REFERENCES "users"("id") ON DELETE CASCADE,
    "achievement_id" TEXT NOT NULL REFERENCES "achievements"("id") ON DELETE CASCADE,
    "unlocked_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP
);
CREATE UNIQUE INDEX "user_achievements_user_id_achievement_id_key" ON "user_achievements"("user_id", "achievement_id");

CREATE TABLE "_EnrolledOppositions" (
    "A" TEXT NOT NULL REFERENCES "oppositions"("id") ON DELETE CASCADE,
    "B" TEXT NOT NULL REFERENCES "users"("id") ON DELETE CASCADE
);
CREATE UNIQUE INDEX "_EnrolledOppositions_AB_unique" ON "_EnrolledOppositions"("A", "B");
CREATE INDEX "_EnrolledOppositions_B_index" ON "_EnrolledOppositions"("B");

