INSERT INTO "subtopics" (id, title, "order", topic_id) VALUES ('693cb876-ab58-42ee-b3b5-225df365fbc6', 'Las fuentes del derecho administrativo', 0, 'c0652ae1-a9b6-4d8f-b7ca-50bc16631309');
INSERT INTO "subtopics" (id, title, "order", topic_id) VALUES ('f09b17c9-c092-4335-b303-8ebb8b2db746', 'El procedimiento administrativo: iniciación, ordenación, instrucción y terminación', 0, 'c0652ae1-a9b6-4d8f-b7ca-50bc16631309');
INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('2b000202-e591-4c4d-af57-4d3c8098e376', '¿En qué año fue aprobada la Constitución Española?', '["1975","1978","1980","1982"]', 1, 'La Constitución Española fue ratificada en referéndum el 6 de diciembre de 1978 y publicada en el BOE el 29 de diciembre de 1978.', 'EASY', '17942a65-32e9-488f-b017-dfd1814ebebf', NULL);
INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('f47d2dcb-b118-4070-ab48-93e5c93d5643', '¿Cuántos títulos tiene la Constitución Española?', '["8 títulos","10 títulos","11 títulos","12 títulos"]', 2, 'La CE tiene un Título Preliminar y 10 Títulos más, sumando un total de 11 títulos.', 'EASY', '17942a65-32e9-488f-b017-dfd1814ebebf', NULL);
INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('a7d22a96-26a5-44da-bee8-8f30543d1099', '¿Según el artículo 1.1 de la CE, cuáles son los valores superiores del ordenamiento jurídico?', '["Libertad, igualdad, justicia y solidaridad","Libertad, justicia, igualdad y pluralismo político","Democracia, libertad, justicia e igualdad","Libertad, igualdad, fraternidad y justicia"]', 1, 'Art. 1.1 CE: "España se constituye en un Estado social y democrático de Derecho, que propugna como valores superiores de su ordenamiento jurídico la libertad, la justicia, la igualdad y el pluralismo político".', 'MEDIUM', '17942a65-32e9-488f-b017-dfd1814ebebf', NULL);
INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('7278ba33-7eed-4416-aa70-fb013f95b294', '¿Cuántos artículos tiene la Constitución Española?', '["155 artículos","160 artículos","169 artículos","175 artículos"]', 2, 'La Constitución Española consta de 169 artículos distribuidos en el Título Preliminar y los Títulos I al X.', 'EASY', '17942a65-32e9-488f-b017-dfd1814ebebf', NULL);
INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('6a375934-e5f6-489a-b1d2-85ec2c1f469b', '¿Cuál es el artículo que regula el derecho a la educación?', '["Artículo 25","Artículo 27","Artículo 28","Artículo 30"]', 1, 'El artículo 27 de la CE reconoce el derecho a la educación y la libertad de enseñanza.', 'MEDIUM', '17942a65-32e9-488f-b017-dfd1814ebebf', NULL);
INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('5414ce8a-5ccf-498c-b6fb-065259b22bed', 'Según la CE, ¿quién es el Jefe del Estado?', '["El Presidente del Gobierno","El Rey","El Presidente del Congreso","El Presidente del Tribunal Constitucional"]', 1, 'Art. 56.1 CE: "El Rey es el Jefe del Estado, símbolo de su unidad y permanencia".', 'EASY', '17942a65-32e9-488f-b017-dfd1814ebebf', NULL);
INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('ad93507e-0521-40e7-aeea-1dcd4e8844e8', '¿Qué mayoría se necesita para una reforma agravada de la CE (art. 168)?', '["Mayoría absoluta de ambas Cámaras","Dos tercios de cada Cámara, disolución, dos tercios de las nuevas Cámaras y referéndum","Tres quintos de ambas Cámaras","Mayoría absoluta del Congreso y mayoría simple del Senado"]', 1, 'El artículo 168 CE establece el procedimiento agravado de reforma: aprobación por 2/3 de cada Cámara, disolución de Cortes, ratificación por las nuevas Cámaras por 2/3 y referéndum.', 'HARD', '17942a65-32e9-488f-b017-dfd1814ebebf', NULL);
INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('9b1f09a7-744b-4ffe-bd5a-14559bbdcf6d', '¿Cuál de estos derechos NO es un derecho fundamental según la Sección 1ª del Capítulo II del Título I?', '["Derecho a la vida (art. 15)","Derecho a la propiedad privada (art. 33)","Derecho a la libertad ideológica (art. 16)","Derecho a la tutela judicial efectiva (art. 24)"]', 1, 'El derecho a la propiedad privada (art. 33) se encuentra en la Sección 2ª del Capítulo II del Título I, no en la Sección 1ª de derechos fundamentales.', 'HARD', '17942a65-32e9-488f-b017-dfd1814ebebf', NULL);
INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('26de2bd2-1a97-492d-a519-77173d596114', '¿Qué artículo de la CE regula el derecho de petición?', '["Artículo 27","Artículo 28","Artículo 29","Artículo 30"]', 2, 'El artículo 29 CE reconoce el derecho de petición individual y colectiva.', 'MEDIUM', '17942a65-32e9-488f-b017-dfd1814ebebf', NULL);
INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('46be57ac-0501-4a76-a61a-7cf84bb11c53', '¿Cuántas disposiciones adicionales tiene la Constitución Española?', '["2","4","6","8"]', 1, 'La CE tiene 4 disposiciones adicionales, 9 transitorias, 1 derogatoria y 1 final.', 'MEDIUM', '17942a65-32e9-488f-b017-dfd1814ebebf', NULL);
INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('516992aa-91c9-49b8-b559-e369567f8acb', '¿Cuántos diputados componen el Congreso de los Diputados?', '["Entre 300 y 400","Exactamente 350","Entre 350 y 400","Entre 300 y 350"]', 0, 'Art. 68.1 CE: El Congreso se compone de un mínimo de 300 y un máximo de 400 Diputados. Actualmente son 350 (fijados por la LOREG).', 'MEDIUM', '84b56817-ec34-456d-ac1b-84f582965092', NULL);
INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('763acee6-7661-4fb0-b185-531004d3db7e', '¿Cuál es la duración del mandato de los Diputados y Senadores?', '["3 años","4 años","5 años","6 años"]', 1, 'Art. 68.4 y 69.6 CE: el mandato de las Cámaras es de cuatro años.', 'EASY', '84b56817-ec34-456d-ac1b-84f582965092', NULL);
INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('9f346f47-755f-4af7-97a1-f5a3cedc0471', '¿Quién propone al candidato a la Presidencia del Gobierno?', '["El Presidente del Congreso","El Rey, previa consulta con los representantes de los grupos políticos","El Presidente del Senado","Los partidos políticos directamente"]', 1, 'Art. 99.1 CE: Tras cada renovación del Congreso, el Rey propondrá un candidato a la Presidencia del Gobierno, previa consulta con los representantes de los grupos políticos.', 'MEDIUM', '84b56817-ec34-456d-ac1b-84f582965092', NULL);
INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('bada5137-2a1b-4931-8c8e-d8ce6c691ca4', '¿Qué órgano juzga la responsabilidad criminal del Presidente del Gobierno?', '["El Tribunal Supremo","La Sala de lo Penal del Tribunal Supremo","El Tribunal Constitucional","La Audiencia Nacional"]', 1, 'Art. 102.1 CE: La responsabilidad criminal del Presidente y los demás miembros del Gobierno será exigible ante la Sala de lo Penal del Tribunal Supremo.', 'HARD', '84b56817-ec34-456d-ac1b-84f582965092', NULL);
INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('6c79e126-2721-43bd-a5a4-8f1400200803', '¿Cuántos miembros componen el Tribunal Constitucional?', '["10 miembros","12 miembros","15 miembros","20 miembros"]', 1, 'Art. 159.1 CE: El Tribunal Constitucional se compone de 12 miembros nombrados por el Rey.', 'EASY', '84b56817-ec34-456d-ac1b-84f582965092', NULL);
INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('47cdb9b6-4af9-4234-8dc0-77326b160098', 'El Defensor del Pueblo es designado por:', '["El Rey","Las Cortes Generales","El Gobierno","El Consejo General del Poder Judicial"]', 1, 'Art. 54 CE: El Defensor del Pueblo es designado por las Cortes Generales como alto comisionado para la defensa de los derechos del Título I.', 'MEDIUM', '84b56817-ec34-456d-ac1b-84f582965092', NULL);
INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('b0475ad1-c21e-486b-b102-d6a9b5aa7210', '¿Cuántos miembros componen el Consejo General del Poder Judicial?', '["12 miembros","15 miembros","20 miembros y el Presidente del TS","21 miembros"]', 2, 'Art. 122.3 CE: El CGPJ está integrado por el Presidente del Tribunal Supremo, que lo presidirá, y por veinte miembros.', 'MEDIUM', '84b56817-ec34-456d-ac1b-84f582965092', NULL);
INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('65b2142e-fe97-40c1-8f51-67381792bac3', '¿Qué artículo de la CE regula la moción de censura?', '["Artículo 112","Artículo 113","Artículo 114","Artículo 115"]', 1, 'El artículo 113 CE regula la moción de censura, que debe ser propuesta al menos por la décima parte de los Diputados e incluir un candidato alternativo.', 'MEDIUM', '84b56817-ec34-456d-ac1b-84f582965092', NULL);
INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('fea9a18a-7698-4085-8dcf-5de96abe5208', '¿Cuál es el plazo máximo general para resolver un procedimiento administrativo según la Ley 39/2015?', '["3 meses","6 meses","1 año","No hay plazo general"]', 0, 'Art. 21.3 Ley 39/2015: Cuando las normas reguladoras del procedimiento no fijen plazo máximo, éste será de tres meses.', 'MEDIUM', '9f05bef5-ae90-4ee5-940f-8b26cfb3a9ef', NULL);
INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('2cf2f65f-64b1-4acc-afe3-5c15aea2f3b2', '¿Qué ley regula el Procedimiento Administrativo Común?', '["Ley 30/1992","Ley 39/2015","Ley 40/2015","Ley 9/2017"]', 1, 'La Ley 39/2015, de 1 de octubre, del Procedimiento Administrativo Común de las Administraciones Públicas, sustituyó a la antigua Ley 30/1992.', 'EASY', '9f05bef5-ae90-4ee5-940f-8b26cfb3a9ef', NULL);
INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('f95606c6-83c5-4762-a2cc-3012b1d23d52', 'Son causas de nulidad de pleno derecho de los actos administrativos, EXCEPTO:', '["Los que lesionen derechos y libertades susceptibles de amparo constitucional","Los dictados por órgano manifiestamente incompetente por razón de materia o territorio","Los que incurran en cualquier infracción del ordenamiento jurídico","Los dictados prescindiendo total y absolutamente del procedimiento"]', 2, 'La infracción del ordenamiento jurídico es causa de anulabilidad (art. 48 Ley 39/2015), no de nulidad de pleno derecho (art. 47).', 'HARD', '9f05bef5-ae90-4ee5-940f-8b26cfb3a9ef', NULL);
INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('e63ed0b2-83d7-4a1c-9e5d-5881f9c453ff', '¿Cuál es el plazo para interponer un recurso de alzada?', '["1 mes si el acto es expreso, 3 meses si es presunto","2 meses si el acto es expreso, 6 meses si es presunto","15 días","1 mes en todo caso"]', 0, 'Art. 122.1 Ley 39/2015: El plazo para interponer recurso de alzada es de un mes (acto expreso) o tres meses (acto presunto por silencio).', 'MEDIUM', '9f05bef5-ae90-4ee5-940f-8b26cfb3a9ef', NULL);
INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('a66e05c0-9102-4683-aee1-c8e359c7f1c0', '¿Qué ley regula el Régimen Jurídico del Sector Público?', '["Ley 6/1997","Ley 39/2015","Ley 40/2015","Real Decreto 364/1995"]', 2, 'La Ley 40/2015, de 1 de octubre, de Régimen Jurídico del Sector Público.', 'EASY', '9f05bef5-ae90-4ee5-940f-8b26cfb3a9ef', NULL);
INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('e4cbb59a-2f28-482d-b9b5-68ad93f0dfe9', '¿Cuál es el plazo para interponer un recurso potestativo de reposición?', '["15 días","1 mes si es acto expreso, 3 meses si es presunto","2 meses","6 meses"]', 1, 'Art. 124.2 Ley 39/2015: El plazo para interponer recurso de reposición es de un mes (acto expreso) o tres meses (silencio administrativo).', 'MEDIUM', '9f05bef5-ae90-4ee5-940f-8b26cfb3a9ef', NULL);
INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('e9e6aada-9998-4910-b185-7a3bd8bcb230', 'El silencio administrativo positivo significa que:', '["La Administración ha resuelto expresamente a favor","Se entiende estimada la solicitud por falta de resolución en plazo","La Administración rechaza la petición","El expediente ha caducado"]', 1, 'El silencio administrativo positivo se produce cuando la Administración no resuelve en plazo y se entiende estimada la solicitud del interesado.', 'MEDIUM', '9f05bef5-ae90-4ee5-940f-8b26cfb3a9ef', NULL);
INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('74eef237-003d-4c4f-a8ee-31f6a843cc1f', '¿Cuánto dura el plazo de prescripción de las infracciones muy graves?', '["6 meses","1 año","2 años","3 años"]', 3, 'Art. 30.1 Ley 40/2015: Las infracciones muy graves prescriben a los tres años, las graves a los dos años y las leves a los seis meses.', 'HARD', '9f05bef5-ae90-4ee5-940f-8b26cfb3a9ef', NULL);
INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('5cbd4444-c041-406f-ab8d-01b058607df8', '¿Qué norma regula el Estatuto Básico del Empleado Público?', '["Ley 30/1984","Real Decreto Legislativo 5/2015 (TREBEP)","Ley 7/2007","Ley 39/2015"]', 1, 'El Real Decreto Legislativo 5/2015, de 30 de octubre, aprobó el Texto Refundido del Estatuto Básico del Empleado Público (TREBEP).', 'EASY', '53abcfda-037e-4c10-9bb8-7c2d2190a347', NULL);
INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('dd7b7c58-4b19-4eb5-9f4c-fb77aaa8f7f1', '¿Cuáles son las clases de personal al servicio de las Administraciones Públicas según el TREBEP?', '["Funcionarios de carrera y personal laboral","Funcionarios de carrera, funcionarios interinos, personal laboral y personal eventual","Funcionarios y contratados","Personal fijo, temporal y eventual"]', 1, 'Art. 8 TREBEP: Los empleados públicos se clasifican en: funcionarios de carrera, funcionarios interinos, personal laboral y personal eventual.', 'MEDIUM', '53abcfda-037e-4c10-9bb8-7c2d2190a347', NULL);
INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('ad13523f-8fce-4aa4-91fb-efbfeba36730', 'Las situaciones administrativas de los funcionarios de carrera incluyen:', '["Servicio activo y jubilación únicamente","Servicio activo, servicios especiales, servicio en otras AAPP, excedencia y suspensión de funciones","Activo, pasivo e interino","Servicio activo, reserva y baja"]', 1, 'Art. 85 TREBEP: Las situaciones administrativas son: servicio activo, servicios especiales, servicio en otras AAPP, excedencia y suspensión de funciones.', 'HARD', '53abcfda-037e-4c10-9bb8-7c2d2190a347', NULL);
INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('8e7fab2e-e985-4754-9668-6038c9c8ed33', '¿Cuál es la duración máxima de la suspensión firme de funciones?', '["3 meses","6 meses","6 años","3 años"]', 2, 'Art. 90.3 TREBEP: La suspensión firme no podrá exceder de 6 años.', 'HARD', '53abcfda-037e-4c10-9bb8-7c2d2190a347', NULL);
INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('80a20dcb-3cd1-46f4-b3eb-7e3a23d0a1ae', '¿Cuáles son los grupos de clasificación profesional del personal funcionario?', '["A, B y C","A1, A2, B, C1 y C2","I, II, III, IV y V","Superior, medio e inferior"]', 1, 'Art. 76 TREBEP: Los cuerpos y escalas se clasifican en los grupos A (subgrupos A1 y A2), B, y C (subgrupos C1 y C2).', 'MEDIUM', '53abcfda-037e-4c10-9bb8-7c2d2190a347', NULL);
INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('083ba6e1-bc9f-44c6-bf30-1e19ec7a34ae', 'La excedencia voluntaria por interés particular requiere haber prestado servicios efectivos durante:', '["Al menos 3 años","Al menos 5 años","Al menos 1 año","No requiere tiempo mínimo"]', 1, 'Art. 89.2 TREBEP: Para solicitar excedencia voluntaria por interés particular se requiere haber prestado servicios efectivos durante un mínimo de 5 años.', 'MEDIUM', '53abcfda-037e-4c10-9bb8-7c2d2190a347', NULL);
INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('56625351-0529-48c2-a05f-ebad48db3397', '¿Cuántos estados miembros tiene actualmente la Unión Europea?', '["25","27","28","30"]', 1, 'Tras el Brexit (2020), la UE cuenta con 27 Estados miembros.', 'EASY', '725fc2c1-d3c4-4d70-83cd-153d38aad4de', NULL);
INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('cd8524e2-ed67-4d76-a42f-85917308e8c2', '¿Cuál es la institución de la UE que tiene la iniciativa legislativa?', '["El Parlamento Europeo","El Consejo de la UE","La Comisión Europea","El Consejo Europeo"]', 2, 'La Comisión Europea es la institución que tiene el monopolio de la iniciativa legislativa en la UE.', 'MEDIUM', '725fc2c1-d3c4-4d70-83cd-153d38aad4de', NULL);
INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('7930611a-c3f5-42a3-977a-b52143cd26cd', '¿Qué tratado estableció la Comunidad Económica Europea?', '["Tratado de Maastricht (1992)","Tratado de Roma (1957)","Tratado de Lisboa (2007)","Tratado de Ámsterdam (1997)"]', 1, 'El Tratado de Roma de 1957 estableció la Comunidad Económica Europea (CEE), firmado por los 6 países fundadores.', 'EASY', '725fc2c1-d3c4-4d70-83cd-153d38aad4de', NULL);
INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('e691e4ed-8444-472a-8ac4-412ac4815eb0', '¿En qué año ingresó España en la Comunidad Europea?', '["1978","1982","1986","1992"]', 2, 'España ingresó en la Comunidad Europea el 1 de enero de 1986, junto con Portugal.', 'EASY', '725fc2c1-d3c4-4d70-83cd-153d38aad4de', NULL);
INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('1738ee58-c367-4696-88fb-1fd00e0e1fb8', 'Los Reglamentos de la UE son:', '["Directamente aplicables en todos los Estados miembros","Necesitan transposición al derecho nacional","Solo vinculan a los Estados a los que van dirigidos","Son meras recomendaciones"]', 0, 'Los Reglamentos de la UE son obligatorios en todos sus elementos y directamente aplicables en cada Estado miembro (art. 288 TFUE).', 'MEDIUM', '725fc2c1-d3c4-4d70-83cd-153d38aad4de', NULL);
INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('27248ad1-6a9d-4557-99d4-883e7f8d88ee', '¿Cuál de estos NO es un principio del Derecho de la UE?', '["Primacía del Derecho de la UE","Efecto directo","Subsidiariedad","Irretroactividad absoluta"]', 3, 'Los principios fundamentales del Derecho de la UE incluyen primacía, efecto directo, subsidiariedad y proporcionalidad. La irretroactividad absoluta no es un principio del Derecho de la UE.', 'HARD', '725fc2c1-d3c4-4d70-83cd-153d38aad4de', NULL);
INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('7411693e-0926-49eb-96e8-f1fdbb05c90a', '¿Qué reglamento europeo regula la protección de datos personales?', '["Directiva 95/46/CE","Reglamento (UE) 2016/679 (RGPD)","Ley Orgánica 15/1999","Reglamento (UE) 2018/302"]', 1, 'El RGPD (Reglamento General de Protección de Datos) es el Reglamento (UE) 2016/679 del Parlamento Europeo y del Consejo.', 'EASY', 'e2c73537-375a-4ef2-b3b7-a09b2518b721', NULL);
INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('c4f4648f-bfa1-453d-bb9f-dea2b5ae5174', '¿Cuál es la edad mínima para que un menor pueda consentir el tratamiento de sus datos en España?', '["13 años","14 años","16 años","18 años"]', 1, 'La LOPDGDD (LO 3/2018) establece en su artículo 7 que en España la edad mínima es de 14 años.', 'MEDIUM', 'e2c73537-375a-4ef2-b3b7-a09b2518b721', NULL);
INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('fbf45f81-b187-4edc-807d-895c26761999', '¿Cuál es el plazo para notificar una brecha de seguridad a la autoridad de control?', '["24 horas","48 horas","72 horas","1 semana"]', 2, 'Art. 33 RGPD: El responsable del tratamiento deberá notificar la brecha a la autoridad de control en un plazo máximo de 72 horas.', 'MEDIUM', 'e2c73537-375a-4ef2-b3b7-a09b2518b721', NULL);
INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('3609edcf-07ac-4cc6-b9e0-cacf763d26fe', '¿Cuáles son los derechos ARCO-POL según la normativa de protección de datos?', '["Acceso, Rectificación, Cancelación y Oposición","Acceso, Rectificación, Cancelación, Oposición, Portabilidad, Olvido y Limitación","Acceso, Revisión, Corrección y Objeción","Autorización, Registro, Control y Observación"]', 1, 'Los derechos ampliados por el RGPD incluyen: Acceso, Rectificación, Supresión (Cancelación/Olvido), Oposición, Portabilidad y Limitación del tratamiento.', 'MEDIUM', 'e2c73537-375a-4ef2-b3b7-a09b2518b721', NULL);
INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('fc835ff2-51a0-451b-a6cd-63dc7dbded20', '¿Qué organismo es la autoridad de control en materia de protección de datos en España?', '["El Ministerio de Justicia","La Agencia Española de Protección de Datos (AEPD)","El Tribunal Constitucional","La Comisión Nacional del Mercado de Valores"]', 1, 'La AEPD es la autoridad pública independiente que vela por el cumplimiento de la normativa de protección de datos en España.', 'EASY', 'e2c73537-375a-4ef2-b3b7-a09b2518b721', NULL);
