INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('1ca29f8a-5e1b-4905-a585-b60ba441db6f', 'En cuanto al papel de la doctrina de los autores, ¿cómo se describe su función en el sistema jurídico?', '["Como fuente principal y obligatoria del Derecho interno.","Como mandatos jurídicos con fuerza coercitiva comparable a la ley.","Como norma que prevalece sobre la ley en casi de conflicto.","Como opiniones y razonamientos que, pese a no formar norma, pueden influir en la creación y reforma de leyes."]', 3, '', 'MEDIUM', '9c2b45c8-32c8-4a99-ba9b-a1069a2b432a', '9c8e3b71-632a-4ccb-96b7-c540b61ec480');
INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('8a8c78a0-beaf-450f-be95-82a1acc7b7d4', 'Respecto a los tratados internacionales, ¿qué requisito es indispensable para que sean aplicables en el ordenamiento español?', '["Que sean dictados mediante decretos-leyes.","Que reemplacen a la ley ordinaria.","Que sean aprobados por referéndum popular.","Que se publiquen íntegramente en el Boletín Oficial del Estado."]', 3, '', 'MEDIUM', '9c2b45c8-32c8-4a99-ba9b-a1069a2b432a', '9c8e3b71-632a-4ccb-96b7-c540b61ec480');
INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('4bf87f78-7c5d-4e2d-b762-a845e334b436', '¿Qué establece el artículo 1.6 del Código Civil sobre la jurisprudencia?', '["Complementará el ordenamiento jurídico con la doctrina del Tribunal Supremo.","Sustituye a la ley en todos los casos.","Es la principal fuente del derecho.","No tiene ninguna relevancia en el ordenamiento jurídico."]', 0, '', 'MEDIUM', '9c2b45c8-32c8-4a99-ba9b-a1069a2b432a', '9c8e3b71-632a-4ccb-96b7-c540b61ec480');
INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('e24c6fc0-679d-4ee2-90fc-3f06c767f89f', '¿Qué tipo de costumbre regula hechos o situaciones no previstos en las leyes?', '["Costumbre interpretativa o secundum legum.","Costumbre internacional.","Costumbre supletoria o extra legem.","Costumbre derogatoria o contra legem."]', 2, '', 'MEDIUM', '9c2b45c8-32c8-4a99-ba9b-a1069a2b432a', '9c8e3b71-632a-4ccb-96b7-c540b61ec480');
INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('3b67fe4f-4e1c-4cf5-b2e3-7dd8dc837071', '¿Cuál es el origen etimológico de la palabra “derecho”?', '["Proviene del griego “dikaios”.","Proviene del árabe “haqq”.","Proviene del germánico “recht”.","Proviene del latín “directus\"."]', 3, '', 'MEDIUM', '9c2b45c8-32c8-4a99-ba9b-a1069a2b432a', '9c8e3b71-632a-4ccb-96b7-c540b61ec480');
INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('0a7532fb-47b2-403f-a847-bc1e3cab0cb3', '¿Qué característica define a una ley constitucional según la Constitución Española?', '["Es la norma suprema del Estado de la que deriva el resto del ordenamiento.","Puede ser promulgada por cualquier órgano legislativo.","Su aprobación, modificación y derogación no requieren procedimientos especiales.","No necesita ser ratificada por el pueblo mediante referéndum."]', 0, '', 'MEDIUM', '9c2b45c8-32c8-4a99-ba9b-a1069a2b432a', '9c8e3b71-632a-4ccb-96b7-c540b61ec480');
INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('d3dfcba3-93bf-4067-af31-ac10576b156b', 'Los principios generales del Derecho se caracterizan por ser:', '["Sentencias emitidas por el Tribunal Supremo.","Reglas secundarias sin función informadora.","Normas no escritas y fundamentales que orientan la interpretación del resto del ordenamiento jurídico.","Directrices exclusivamente doctrinales sin valor normativo."]', 2, '', 'MEDIUM', '9c2b45c8-32c8-4a99-ba9b-a1069a2b432a', '9c8e3b71-632a-4ccb-96b7-c540b61ec480');
INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('c0785920-96ce-4e00-a447-5ab6d4ef99e5', '¿Cuál es el papel que desempeña la jurisprudencia en el ordenamiento jurídico español?', '["Es la fuente primaria obligatoria para resolver todos los conflictos jurídicos.","Sustituye a la ley en los casos de lagunas normativas.","Complementa la ley, la costumbre y los principios generales del derecho a través de criterios reiterados en las sentencias del Tribunal Supremo.","Es el conjunto de opiniones doctrinales del Tribunal Constitucional."]', 2, '', 'MEDIUM', '9c2b45c8-32c8-4a99-ba9b-a1069a2b432a', '9c8e3b71-632a-4ccb-96b7-c540b61ec480');
INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('54268a87-c2f3-4c10-8a8e-7a07787db8c3', '¿Cuál de las siguientes materias se incluye dentro del Derecho civil?', '["Derecho administrativo y derecho penal.","Derecho internacional y derecho comunitario.","Derecho mercantil y derecho laboral.","Derecho de la persona, derecho patrimonial privado, derecho de familia y derecho de sucesiones."]', 3, '', 'MEDIUM', '9c2b45c8-32c8-4a99-ba9b-a1069a2b432a', '9c8e3b71-632a-4ccb-96b7-c540b61ec480');
INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('d3d5b8bc-4f0f-4d0d-86a0-c2daae2594ad', '¿Cuál es la principal diferencia entre los principios generales del derecho y la costumbre?', '["La costumbre tiene carácter informador del ordenamiento jurídico.","Los principios generales del derecho carecen de formulación escrita.","Los principios generales del derecho requieren del uso para su afirmación.","La costumbre no necesita ser probada para ser aplicada."]', 1, '', 'MEDIUM', '9c2b45c8-32c8-4a99-ba9b-a1069a2b432a', '9c8e3b71-632a-4ccb-96b7-c540b61ec480');
