INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('1329f3ec-20fa-4899-b871-a5f775159945', '¿Qué se entiende por "fuente formal" del derecho?', '["Costumbres locales y regionales.","Normas jurídicas contenidas en tratados internacionales.","Aquellas que están fuera del propio derecho y son externas.","Aquellas que están dentro del propio derecho y son internas."]', 3, '', 'MEDIUM', '9c2b45c8-32c8-4a99-ba9b-a1069a2b432a', '9c8e3b71-632a-4ccb-96b7-c540b61ec480');
