INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('a46dac7c-41fc-4bfb-9370-80b3b7722b67', '¿Cuál es la principal diferencia entre la ley y la costumbre?', '["La ley se basa en repetición de actos.","La ley impone sanciones y la costumbre tradición.","La ley es escrita y la costumbre surge de la repetición social.","La ley es oral y la costumbre escrita."]', 2, '', 'MEDIUM', '9c2b45c8-32c8-4a99-ba9b-a1069a2b432a', '9c8e3b71-632a-4ccb-96b7-c540b61ec480');
INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('e53cb551-2c73-4f3f-a817-7df49b20195a', '¿Qué establece el artículo 93 de la Constitución Española?', '["Pueden ser aprobados por cualquier órgano.","No tienen relevancia.","No necesitan ratificación.","Pueden atribuir competencias a organizaciones internacionales."]', 3, '', 'MEDIUM', '9c2b45c8-32c8-4a99-ba9b-a1069a2b432a', '9c8e3b71-632a-4ccb-96b7-c540b61ec480');
