INSERT INTO "questions" (id, question_text, options, correct_index, explanation, difficulty, topic_id, subtopic_id) VALUES ('95756a29-6a67-4850-b916-be11c4c1a4fd', 'En relación con la costumbre, ¿cuál es correcta?', '["Tiene prioridad sobre la ley.","Se aplica en derecho penal.","Es siempre escrita.","Solo se aplica en defecto de ley y sin contradecir moral u orden público."]', 3, '', 'MEDIUM', '9c2b45c8-32c8-4a99-ba9b-a1069a2b432a', '9c8e3b71-632a-4ccb-96b7-c540b61ec480');
